/**
 * Split-Flap Panel — a CSS-3D recreation of Solari-style departure boards.
 * Built by Cody Shanley · https://codyshanley.com/playground/split-flap?utm_source=github&utm_medium=attribution&utm_campaign=split-flap
 * MIT licensed. Free to use, modify, and redistribute.
 */
"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { SplitFlapSlat } from "./split-flap-slat";
import "./split-flap.css";

interface Props {
  words: string[];
  /** The deterministic initial word. Defaults to the first word. */
  anchorWord?: string;
  slotCount?: number;
  stepMs?: number;
  slotStaggerMs?: number;
  size?: "default" | "xl" | "compact" | "hero";
  /** When this number changes, advance immediately to the next word. */
  refreshSignal?: number;
  /** Announce each word after every slat has settled. */
  announce?: boolean;
}

function padToSlots(word: string, slotCount: number): string[] {
  const chars = Array.from(word.toUpperCase());
  return Array.from({ length: slotCount }, (_, index) => chars[index] ?? " ");
}

function nextWord(words: string[], current: string): string {
  if (words.length === 0) return current;
  return words[(words.indexOf(current) + 1) % words.length] ?? current;
}

function semanticWord(word: string, slotCount: number): string {
  return Array.from(word).slice(0, slotCount).join("").trimEnd();
}

export function SplitFlapDisplay({
  words,
  anchorWord,
  slotCount = 8,
  stepMs = 110,
  slotStaggerMs = 40,
  size = "default",
  refreshSignal,
  announce = false,
}: Props) {
  const normalizedSlotCount = Number.isFinite(slotCount)
    ? Math.max(0, Math.floor(slotCount))
    : 8;
  const initialWord = useRef(anchorWord ?? words[0] ?? "").current;
  const [currentWord, setCurrentWord] = useState(initialWord);
  const [initialLetters] = useState(() => padToSlots(initialWord, normalizedSlotCount));
  const [settledWord, setSettledWord] = useState(() =>
    semanticWord(initialWord, normalizedSlotCount),
  );
  const previousRefreshSignal = useRef(refreshSignal);

  useEffect(() => {
    if (Object.is(refreshSignal, previousRefreshSignal.current)) return;
    previousRefreshSignal.current = refreshSignal;
    setCurrentWord((current) => nextWord(words, current));
  }, [refreshSignal, words]);

  const targets = useMemo(
    () => padToSlots(currentWord, normalizedSlotCount),
    [currentWord, normalizedSlotCount],
  );
  const targetsRef = useRef(targets);
  const currentWordRef = useRef(currentWord);
  const settledTargetsRef = useRef([...targets]);
  targetsRef.current = targets;
  currentWordRef.current = currentWord;

  const handleSlatSettled = useCallback((index: number, target: string) => {
    const activeTargets = targetsRef.current;
    if (activeTargets[index] !== target) return;
    settledTargetsRef.current[index] = target;
    if (activeTargets.every((character, position) => settledTargetsRef.current[position] === character)) {
      setSettledWord(semanticWord(currentWordRef.current, activeTargets.length));
    }
  }, []);

  useEffect(() => {
    if (targets.every((character, index) => settledTargetsRef.current[index] === character)) {
      setSettledWord(semanticWord(currentWord, targets.length));
    }
  }, [currentWord, targets]);

  return (
    <span className="splitflap-display">
      <span
        className="splitflap-sr-only"
        role={announce ? "status" : undefined}
        aria-live={announce ? "polite" : "off"}
        aria-atomic={announce ? "true" : undefined}
      >
        {settledWord}
      </span>
      {targets.map((target, index) => (
        <SplitFlapSlat
          key={index}
          target={target}
          initialCurrent={initialLetters[index] ?? " "}
          stepMs={stepMs}
          startDelayMs={index * slotStaggerMs}
          minFlips={1}
          size={size}
          onSettled={(settledTarget) => handleSlatSettled(index, settledTarget)}
        />
      ))}
    </span>
  );
}

/**
 * Split-Flap Panel — a CSS-3D recreation of Solari-style departure boards.
 * Built by Cody Shanley · https://codyshanley.com/playground/split-flap?utm_source=github&utm_medium=attribution&utm_campaign=split-flap
 * MIT licensed. Free to use, modify, and redistribute.
 */
"use client";

import { useEffect, useRef, useState } from "react";

export const SPLITFLAP_ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789. ";

function nextChar(c: string): string {
  const i = SPLITFLAP_ALPHABET.indexOf(c);
  return SPLITFLAP_ALPHABET[(i + 1) % SPLITFLAP_ALPHABET.length] ?? " ";
}

/** Forward-only distance from `from` to `to` on the one-way alphabet chain.
 *  Matches real Solari motion: X -> D = 18 through the remaining alphabet. */
export function computeFlipCount(from: string, to: string): number {
  const a = SPLITFLAP_ALPHABET.indexOf(from);
  const b = SPLITFLAP_ALPHABET.indexOf(to);
  if (a < 0 || b < 0) return 0;
  return (b - a + SPLITFLAP_ALPHABET.length) % SPLITFLAP_ALPHABET.length;
}

interface Props {
  target: string;
  stepMs?: number;
  startDelayMs?: number;
  minFlips?: number;
  onFlip?: () => void;
  onSettled?: (target: string) => void;
  size?: "default" | "xl" | "compact" | "hero";
  /** Freeze the slat in a mid-flip pose for visual inspection. Disables animation. */
  frozenMidFlip?: boolean;
  /** Debug: override the letters shown. Useful for static reference slats. */
  staticLetter?: string;
  /** Letter to display as the initial state without animation. Read once at mount. */
  initialCurrent?: string;
}

export function SplitFlapSlat({
  target,
  stepMs = 110,
  startDelayMs = 0,
  minFlips = 1,
  onFlip,
  onSettled,
  size = "default",
  frozenMidFlip = false,
  staticLetter,
  initialCurrent,
}: Props) {
  const [current, setCurrent] = useState<string>(staticLetter ?? initialCurrent ?? " ");
  const [next, setNext] = useState<string | null>(null);
  const [isFlipping, setIsFlipping] = useState(false);
  const currentRef = useRef(current);
  const onFlipRef = useRef(onFlip);
  const onSettledRef = useRef(onSettled);
  onFlipRef.current = onFlip;
  onSettledRef.current = onSettled;

  useEffect(() => {
    currentRef.current = current;
  }, [current]);

  useEffect(() => {
    if (staticLetter !== undefined || frozenMidFlip) return;

    let cancelled = false;
    let finished = false;
    let timer: ReturnType<typeof setTimeout> | undefined;
    let pending: { run: () => void; remaining: number; startedAt: number } | undefined;
    const motionQuery = window.matchMedia?.("(prefers-reduced-motion: reduce)");

    const finish = (value: string) => {
      if (cancelled || finished) return;
      finished = true;
      currentRef.current = value;
      setCurrent(value);
      setIsFlipping(false);
      setNext(null);
      onSettledRef.current?.(value);
    };

    const arm = () => {
      if (cancelled || !pending || document.hidden) return;
      const task = pending;
      task.startedAt = Date.now();
      timer = setTimeout(() => {
        timer = undefined;
        if (pending !== task) return;
        pending = undefined;
        task.run();
      }, task.remaining);
    };

    const schedule = (run: () => void, delay: number) => {
      pending = { run, remaining: Math.max(0, delay), startedAt: 0 };
      arm();
    };

    const pause = () => {
      if (timer === undefined || !pending) return;
      clearTimeout(timer);
      timer = undefined;
      pending.remaining = Math.max(0, pending.remaining - (Date.now() - pending.startedAt));
    };

    const handleVisibilityChange = () => {
      if (document.hidden) pause();
      else arm();
    };

    const snapToTarget = () => {
      pause();
      pending = undefined;
      finish(target);
    };

    setIsFlipping(false);
    setNext(null);

    if (
      motionQuery?.matches ||
      !SPLITFLAP_ALPHABET.includes(currentRef.current) ||
      !SPLITFLAP_ALPHABET.includes(target)
    ) {
      snapToTarget();
      return;
    }

    const flipsNeeded = () => {
      let distance = computeFlipCount(currentRef.current, target);
      if (distance !== 0 && distance < minFlips) distance += SPLITFLAP_ALPHABET.length;
      return distance;
    };

    const runFlip = (remaining: number) => {
      if (cancelled) return;
      if (remaining <= 0) {
        finish(target);
        return;
      }
      const nextCharacter = nextChar(currentRef.current);
      setNext(nextCharacter);
      setIsFlipping(true);
      onFlipRef.current?.();

      schedule(() => {
        if (cancelled) return;
        currentRef.current = nextCharacter;
        setCurrent(nextCharacter);
        setIsFlipping(false);
        setNext(null);
        schedule(() => runFlip(remaining - 1), 18);
      }, stepMs);
    };

    document.addEventListener("visibilitychange", handleVisibilityChange);
    motionQuery?.addEventListener("change", snapToTarget, { once: true });
    schedule(() => {
      const count = flipsNeeded();
      if (count === 0) finish(target);
      else runFlip(count);
    }, startDelayMs);

    return () => {
      cancelled = true;
      if (timer !== undefined) clearTimeout(timer);
      pending = undefined;
      document.removeEventListener("visibilitychange", handleVisibilityChange);
      motionQuery?.removeEventListener("change", snapToTarget);
    };
  }, [target, stepMs, startDelayMs, minFlips, staticLetter, frozenMidFlip]);

  const displayCurrent = staticLetter ?? current;
  const displayNext = frozenMidFlip ? nextChar(displayCurrent) : next;
  const showFlippers = frozenMidFlip || (isFlipping && displayNext !== null);

  return (
    <span
      className={`splitflap-slat${
        size === "xl"
          ? " splitflap-slat--xl"
          : size === "compact"
            ? " splitflap-slat--compact"
            : size === "hero"
              ? " splitflap-slat--hero"
              : ""
      }`}
      aria-hidden="true"
    >
      <span className="splitflap-inner">
        <span className="splitflap-half splitflap-half--top">
          <span className="splitflap-letter">
            {showFlippers && displayNext !== null ? displayNext : displayCurrent}
          </span>
        </span>
        <span className="splitflap-half splitflap-half--bottom">
          <span className="splitflap-letter">{displayCurrent}</span>
        </span>
        {showFlippers && displayNext !== null && (
          <>
            <span
              className={`splitflap-flipping-top${
                frozenMidFlip ? " splitflap-flipping-top--frozen" : ""
              }`}
              key={`ft-${displayCurrent}-${displayNext}`}
            >
              <span className="splitflap-letter">{displayCurrent}</span>
            </span>
            <span
              className={`splitflap-flipping-bottom${
                frozenMidFlip ? " splitflap-flipping-bottom--frozen" : ""
              }`}
              key={`fb-${displayCurrent}-${displayNext}`}
            >
              <span className="splitflap-letter">{displayNext}</span>
            </span>
          </>
        )}
      </span>
    </span>
  );
}

/**
 * Split-Flap Panel — a CSS-3D recreation of Solari-style departure boards.
 * Built by Cody Shanley · https://codyshanley.com/playground/split-flap?utm_source=github&utm_medium=attribution&utm_campaign=split-flap
 * MIT licensed. Free to use, modify, and redistribute.
 *
 * Font: override with --splitflap-font if you want a specific typeface.
 * Colors: override per-slat with --slat-ink, --slat-top-grad-a, etc.
 */

/* ============ SPLIT-FLAP DISPLAY ============ */
/* Solari-style flipclock mechanism. Four stacked panels inside a perspective
   container:
   - static top (shows target letter top half, clipped)
   - static bottom (shows current letter bottom half, clipped)
   - flipping top  (current letter, rotates 0 to -90 on X, first half of flip)
   - flipping bottom (target letter,  rotates 90 to 0 on X, second half)
   Letter spans full inner slat height, flexbox-centered, clipped by each half. */

.splitflap-display {
  display: inline-flex;
  align-items: center;
  max-width: 100%;
  gap: 3px;
  overflow-x: auto;
  overflow-y: hidden;
  overscroll-behavior-inline: contain;
  vertical-align: baseline;
  line-height: 1;
}

.splitflap-sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.splitflap-slat {
  --slat-width: 42px;
  --slat-height: 62px;
  --slat-font-size: calc(var(--slat-height) * 0.68);
  --slat-ink: #1A1A19;
  --slat-seam-fill: rgba(30, 27, 20, 0.2);
  --slat-top-grad-a: rgba(253, 252, 249, 0.8);
  --slat-top-grad-b: rgba(242, 240, 234, 0.8);
  --slat-bottom-grad-a: rgba(237, 235, 229, 0.8);
  --slat-bottom-grad-b: rgba(247, 245, 239, 0.8);

  display: inline-block;
  flex: 0 0 auto;
  position: relative;
  width: var(--slat-width);
  height: var(--slat-height);
  background: transparent;
  border-radius: 5px;
  padding: 0;
  perspective: 240px;
  filter: drop-shadow(0 3px 6px rgba(0, 0, 0, 0.14)) drop-shadow(0 1px 2px rgba(0, 0, 0, 0.08));
  vertical-align: middle;
  font-family: var(--splitflap-font, system-ui, -apple-system, "Segoe UI", sans-serif);
  line-height: 1;
}

.splitflap-inner {
  display: block;
  position: relative;
  width: 100%;
  height: 100%;
  transform-style: preserve-3d;
}

/* Half clippers — static panels visible when slat is at rest */
.splitflap-half {
  position: absolute;
  left: 0;
  right: 0;
  height: 50%;
  overflow: hidden;
  backface-visibility: hidden;
  -webkit-backface-visibility: hidden;
  transform: translateZ(0); /* force GPU layer — Safari backface fix */
}

.splitflap-half--top {
  top: 0;
  background: linear-gradient(180deg, var(--slat-top-grad-a) 0%, var(--slat-top-grad-b) 100%);
  border-radius: 5px 5px 0 0;
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.6),
    inset 0 -4px 5px -4px rgba(0, 0, 0, 0.07);
}

.splitflap-half--bottom {
  bottom: 0;
  background: linear-gradient(180deg, var(--slat-bottom-grad-a) 0%, var(--slat-bottom-grad-b) 100%);
  border-radius: 0 0 5px 5px;
  box-shadow:
    inset 0 4px 5px -4px rgba(0, 0, 0, 0.09),
    inset 0 -1px 0 rgba(0, 0, 0, 0.04);
}

/* Letter: full inner-slat height, flexbox-centered. The overflow:hidden
   on each half clips it to show only the top or bottom half of the glyph. */
.splitflap-letter {
  position: absolute;
  left: 0;
  right: 0;
  height: 200%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: var(--slat-font-size);
  color: var(--slat-ink);
  line-height: 1;
  letter-spacing: 0;
  user-select: none;
  pointer-events: none;
  text-shadow:
    0 -1px 0 rgba(255, 255, 255, 0.48),
    0 1px 1px rgba(0, 0, 0, 0.38),
    0 2px 2px rgba(0, 0, 0, 0.15);
}

.splitflap-half--top .splitflap-letter,
.splitflap-flipping-top .splitflap-letter { top: 0; }

.splitflap-half--bottom .splitflap-letter,
.splitflap-flipping-bottom .splitflap-letter { bottom: 0; }

/* Flipping pieces — same visual as the static halves, but animated */
.splitflap-flipping-top,
.splitflap-flipping-bottom {
  position: absolute;
  left: 0;
  right: 0;
  height: 50%;
  overflow: hidden;
  backface-visibility: hidden;
  -webkit-backface-visibility: hidden;
  z-index: 2;
}

.splitflap-flipping-top {
  top: 0;
  background: linear-gradient(180deg, var(--slat-top-grad-a) 0%, var(--slat-top-grad-b) 100%);
  border-radius: 5px 5px 0 0;
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.6),
    inset 0 -4px 5px -4px rgba(0, 0, 0, 0.07);
  transform-origin: bottom center;
  animation: splitflap-fold 50ms ease-in forwards;
}

.splitflap-flipping-bottom {
  bottom: 0;
  background: linear-gradient(180deg, var(--slat-bottom-grad-a) 0%, var(--slat-bottom-grad-b) 100%);
  border-radius: 0 0 5px 5px;
  box-shadow:
    inset 0 4px 5px -4px rgba(0, 0, 0, 0.09),
    inset 0 -1px 0 rgba(0, 0, 0, 0.04);
  transform-origin: top center;
  transform: rotateX(90deg);
  animation: splitflap-unfold 60ms ease-out 50ms forwards;
}

@keyframes splitflap-fold {
  0%   { transform: rotateX(0deg);   filter: brightness(1); }
  100% { transform: rotateX(-90deg); filter: brightness(0.72); }
}

@keyframes splitflap-unfold {
  0%   { transform: rotateX(90deg); filter: brightness(0.72); }
  100% { transform: rotateX(0deg);  filter: brightness(1); }
}

/* Frozen mid-flip — for prototype inspection only */
.splitflap-flipping-top--frozen {
  animation: none !important;
  transform: rotateX(-45deg) !important;
}
.splitflap-flipping-bottom--frozen {
  animation: none !important;
  transform: rotateX(45deg) !important;
}

/* Size modifiers */
.splitflap-slat--xl {
  --slat-width: 120px;
  --slat-height: 180px;
}

.splitflap-slat--compact {
  --slat-width: 28px;
  --slat-height: 42px;
}

.splitflap-slat--hero {
  --slat-width: 28px;
  --slat-height: 40px;
}

@media (prefers-reduced-motion: reduce) {
  .splitflap-flipping-top,
  .splitflap-flipping-bottom {
    display: none !important;
  }
}

/* ============ SPLIT-FLAP — NO-CARD VARIANT ============ */
/* Strips gradients, shadows, and rounded corners so only the letters flip.
   Apply by wrapping the display in a `.splitflap-nocard` scope. */

.splitflap-nocard .splitflap-slat {
  filter: none;
}

.splitflap-nocard .splitflap-letter {
  text-shadow: none;
}

.splitflap-nocard .splitflap-half--top,
.splitflap-nocard .splitflap-half--bottom,
.splitflap-nocard .splitflap-flipping-top,
.splitflap-nocard .splitflap-flipping-bottom {
  background: none;
  box-shadow: none;
  border-radius: 0;
}

.splitflap-nocard .splitflap-slat:has(.splitflap-flipping-top) .splitflap-half--top,
.splitflap-nocard .splitflap-slat:has(.splitflap-flipping-bottom) .splitflap-half--bottom {
  visibility: hidden;
}
